  ('gerber-daisy', 'Gerber Daisy', 'Gerbera jamesonii', ARRAY['African Daisy', 'Barberton Daisy']::text[], ARRAY['red', 'pink', 'orange', 'yellow', 'white']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/gerber-daisy.jpg?itok=W0zK63vb', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/gerber-daisy.jpg?itok=W0zK63vb', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/gerber-daisy.jpg?itok=hKgtHOZl']::text[], 'non_toxic', NULL, NULL),
  ('begonia', 'Begonia', 'Begonia spp.', ARRAY['Elephant-Ear Begonia', 'Iron Cross Begonia', 'Mapleleaf Begonia', 'Metallic Leaf Begonia', 'Peace Begonia', 'Pink Pearl']::text[], ARRAY['pink', 'red', 'white', 'orange']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/begonia-r.jpg?itok=JYOkAKBU', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/begonia-r.jpg?itok=JYOkAKBU', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/begonia-r.jpg?itok=ptv4qEhB']::text[], 'mildly_toxic', 'Kidney failure (in grazing animals), vomiting, salivation in dogs/cats. Most toxic part is underground.', 'Soluble calcium oxalates'),
  ('chrysanthemum', 'Chrysanthemum', 'Chrysanthemum spp.', ARRAY['Mum']::text[], ARRAY['white', 'yellow', 'pink', 'red', 'orange']::text[], 'https://www.aspca.org/sites/default/files/chrysanthemum-r.jpg?itok=uRlMg9mx', ARRAY['https://www.aspca.org/sites/default/files/chrysanthemum-r.jpg?itok=uRlMg9mx', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/chrysanthemum-r.jpg?itok=Ae5RXClT']::text[], 'mildly_toxic', 'Vomiting, diarrhea, hypersalivation, incoordination, dermatitis', 'Sesquiterpene, lactones, pyrethrins and other potential irritants'),
  ('cyclamen', 'Cyclamen', 'Cyclamen spp', ARRAY['Sowbread']::text[], ARRAY['pink', 'red', 'white', 'purple']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/cyclamen-2-r.jpg?itok=Rjy8SICM', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/cyclamen-2-r.jpg?itok=Rjy8SICM', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/cyclamen-2-r.jpg?itok=DHmReL_p']::text[], 'highly_toxic', 'Salivation, vomiting, diarrhea. Following large ingestions of tubers: heart rhythm abnormalities, seizures, death', 'Terpenoid saponins'),
  ('amaryllis', 'Amaryllis', 'Amaryllis spp.', ARRAY['Naked Lady']::text[], ARRAY['red', 'white', 'pink']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/amaryllis-300x200.jpg?itok=DGvJ5GOY', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/amaryllis-300x200.jpg?itok=DGvJ5GOY', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/amaryllis-300x200.jpg?itok=a7iUtN0L']::text[], 'mildly_toxic', 'Vomiting (not horses), depression, diarrhea, abdominal pain, hypersalivation, anorexia, tremors.', 'Lycorine and others'),
  ('tulip', 'Tulip', 'Tulipa spp.', ARRAY['Garden Tulip']::text[], ARRAY['red', 'yellow', 'pink', 'purple', 'white', 'orange']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/tulip-r.jpg?itok=4MPaC14J', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/tulip-r.jpg?itok=4MPaC14J', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/tulip-r.jpg?itok=B-lc2CB_']::text[], 'mildly_toxic', 'Vomiting, depression, diarrhea, hypersalivation. Highest concentration of toxin in bulb.', 'Tulipalin A and B'),
  ('hyacinth', 'Hyacinth', 'Hyacinthus orientalis', ARRAY['Garden Hyacinth']::text[], ARRAY['purple', 'pink', 'white', 'blue']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/hyacinth-r.jpg?itok=2FwxWCFi', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/hyacinth-r.jpg?itok=2FwxWCFi', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/hyacinth-r.jpg?itok=ecEK9wH-']::text[], 'mildly_toxic', 'Intense vomiting, diarrhea, occassionally with blood, depression and tremors.', 'Possibly narcissus-like alkaloids'),
  ('daffodil', 'Daffodil', 'Narcissus spp', ARRAY['Narcissus', 'Paper White']::text[], ARRAY['yellow', 'white']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/daffodil-r.jpg?itok=h1h9GpYw', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/daffodil-r.jpg?itok=h1h9GpYw', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/daffodil-r.jpg?itok=1CHoGWD7']::text[], 'highly_toxic', 'Vomiting, salvation, diarrhea; large ingestions cause convulsions, low blood pressure, tremors and cardiac arrhythmias. Bulbs are the most poisonous part.', 'Lycorine and other alkaloids'),
  ('lily', 'Lily', 'Lilium species', ARRAY['Asian Lily', 'Easter Lily', 'Japanese Show Lily', 'Red Lily', 'Rubrum Lily', 'Stargazer Lily']::text[], ARRAY['white', 'pink', 'orange', 'yellow']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/lily-r.jpg?itok=ui0jyYmE', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/lily-r.jpg?itok=ui0jyYmE', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/lily-r.jpg?itok=PJ1P0twf']::text[], 'highly_toxic', 'Cats: kidney failure.', NULL),
  ('cast-iron-plant', 'Cast Iron Plant', 'Aspidistra elatior', ARRAY['Bar Room Plant', 'Aspidistra']::text[], ARRAY['green']::text[], 'https://www.aspca.org/sites/default/files/image.jpg?itok=8YzgQQwh', ARRAY['https://www.aspca.org/sites/default/files/image.jpg?itok=8YzgQQwh', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/image.jpg?itok=uoo7WHfL']::text[], 'non_toxic', NULL, NULL),
  ('aluminum-plant', 'Aluminum Plant', 'Pilea cadieri', ARRAY['Watermelon Pilea']::text[], ARRAY['green', 'white']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/aluminum-plant.jpg?itok=1BUoOyUo', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/aluminum-plant.jpg?itok=1BUoOyUo', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/aluminum-plant.jpg?itok=ClEm10dV']::text[], 'non_toxic', NULL, NULL),
  ('friendship-plant', 'Friendship Plant', 'Pilea involucrata', ARRAY['Panamiga']::text[], ARRAY['green', 'pink']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/friendship-plant.jpg?itok=Q7kBJEwy', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/friendship-plant.jpg?itok=Q7kBJEwy', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/friendship-plant.jpg?itok=sPWFCB3g']::text[], 'non_toxic', NULL, NULL),
  ('polka-dot-plant', 'Polka Dot Plant', 'Hypoestes phyllostachya', ARRAY['Baby’s Tears', 'Freckle Face', 'Pink Splash']::text[], ARRAY['pink', 'white', 'red']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/babys-tears-r_0.jpg?itok=wxSANWbs', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/babys-tears-r_0.jpg?itok=wxSANWbs', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/babys-tears-r_0.jpg?itok=xonmck6U']::text[], 'non_toxic', NULL, NULL),
  ('nerve-plant', 'Nerve Plant', 'Fittonia verschaffeltii', ARRAY['Fittonia', 'Mosaic Plant']::text[], ARRAY['pink', 'white']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/babys-tears-r_0.jpg?itok=wxSANWbs', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/babys-tears-r_0.jpg?itok=wxSANWbs', 'https://www.aspca.org/sites/default/files/field/image/plants/prayer-plant.jpg?itok=BHkjAc4V']::text[], 'non_toxic', NULL, NULL),
  ('asparagus-fern', 'Asparagus Fern', 'Asparagus densiflorus cv sprengeri', ARRAY['Lace Fern', 'Plumosa Fern', 'Racemose asparagus', 'Shatavari', 'Sprengeri Fern']::text[], ARRAY['green']::text[], 'https://www.aspca.org/sites/default/files/field/image/plants/asparagus-fern-r.jpg?itok=YNshxWGZ', ARRAY['https://www.aspca.org/sites/default/files/field/image/plants/asparagus-fern-r.jpg?itok=YNshxWGZ', 'https://www.aspca.org/sites/default/files/styles/plant_listing_180x120/public/field/image/plants/asparagus-fern-r.jpg?itok=KOrjpOWE']::text[], 'mildly_toxic', 'Allergic dermatitis with repeated dermal exposure. Berry ingestion could result in gastric upset (vomiting, abdominal pain, or diarrhea).', NULL);

